#![feature(fmt_internals)]

use core::panic::Location;

extern "Rust" {
    fn panic_fmt_loc(fmt: core::fmt::Arguments<'_>, loc: &'static Location<'static>) -> !;
}

fn panic_assertion_failed(msg: &str, location: &'static Location<'static>) -> ! {
    unsafe {
        panic_fmt_loc(core::fmt::Arguments::new_const(&[msg]), location)
    }
}

fn panic_index_out_of_bounds(index: usize, len: usize, _loc: &core::panic::Location) -> ! {
    panic!("index out of bounds: the len is {len} but the index is {index}")
}

use core::fmt;
use core::panic::Location;

#[track_caller]
fn unwrap_failed(_msg: &str, _error: &dyn fmt::Debug, _caller: &Location) -> ! {
    panic!("{}: {:?}", _msg, _error)
}

use core::panic::Location;

pub fn panic_overflow_sub(_loc: &'static Location<'static>) -> ! {
    let pieces_ptr: *const &'static str = &"attempt to subtract with overflow";
    let pieces_len: usize = 1;
    let fmt_args_len: usize = 8;
    let fmt_args_data: u128 = 0;
    let _ = (pieces_len, fmt_args_len, fmt_args_data);
    let rdi: *const *const &'static str = &pieces_ptr;
    let fn_0x5555556c96f0: extern "C" fn(*const *const &'static str) = unsafe { core::mem::transmute(rdi) };
    fn_0x5555556c96f0(rdi);
    loop {}
}

#[repr(C)]
pub struct MarginRequirementResult {
    pub kind: u64,
    pub price_lo: u64,
    pub price_hi: u64,
    pub notional_lo: u64,
    pub notional_hi: u64,
    pub size_lo: u64,
    pub size_hi: u64,
    pub mark_lo: u64,
    pub mark_hi: u64,
    pub margin_type: u64,
    pub margin_req: u64,
    pub margin_addl: u64,
    pub abs_notional_lo: u64,
    pub abs_notional_hi: u64,
    pub flags: u64,
}

#[repr(C)]
pub struct MarginSpec {
    pub margin_type: u64,
    pub margin_req: u64,
    pub margin_addl: u64,
}

#[repr(C)]
pub struct Position {
    pub asset_id: u64,
    pub side: u64,
    pub szi: i64,
    pub mid: [u8; 0x60],
    pub margin: MarginSpec,
    pub max_leverage_alt: u64,
    pub max_leverage: u8,
    pub tail: [u8; 0x8],
}

#[repr(C)]
pub struct OraclePx {
    pub px_lo: u64,
    pub px_hi: u64,
    pub timestamp: u64,
    pub mark: i64,
}

extern "C" {
    fn oracle_price_type_validate(scratch: &mut u128, px_lo: u64, px_hi: u64) -> (u64, u64);
    fn option_unit_qty_add_a(unit: &u64, scratch: &u128) -> (u64, u64);
}

pub fn compute_margin_requirement_by_mode(this: &Position, oracle_px: &OraclePx) -> MarginRequirementResult {
    let signed_notional_p = oracle_px;
    let position_size = this;

    let pos_szi = position_size.szi;
    let abs_notional_1 = (signed_notional_p.mark as i64).wrapping_mul(pos_szi);

    let mut oqu_scratch: u128 =
        (signed_notional_p.px_lo as u128) | ((signed_notional_p.px_hi as u128) << 64);
    let (price_oqu_tag_1, oracle_price_val_2) = unsafe {
        oracle_price_type_validate(&mut oqu_scratch, signed_notional_p.px_lo, signed_notional_p.px_hi)
    };
    let oracle_price_val = oracle_price_val_2;
    let price_oqu_tag_2: u64 = 2;
    let price_oqu_tag = if abs_notional_1 == 0 { 2 } else { price_oqu_tag_1 };
    let oracle_price_val_1 = oracle_price_val;
    let price_oqu_unit = price_oqu_tag;

    let neg = abs_notional_1.wrapping_neg();
    let abs_notional: u64 = if neg < 0 { abs_notional_1 as u64 } else { neg as u64 };

    let margin_mode: u8 = position_size.margin.margin_type as u8;
    let mut margin_result: u64 = margin_mode as u64;
    let mut divisor: u64 = 0;
    let mut leverage: u64 = 0;
    let mut max_leverage: u64 = 0;
    let mut adl_divisor_byte: u8 = 0;
    let mut adl_divisor: u64 = 0;

    match margin_mode {
        0 => { margin_result = 0; }
        1 => {
            let rax_1: u8 = (position_size.margin.margin_type as u8 != 3) as u8;
            let off = 0x80usize + ((rax_1 as usize) << 4);
            divisor = unsafe {
                *((position_size as *const Position as *const u8).add(off) as *const u64)
            };
            leverage = divisor;
            if divisor != 0 && abs_notional >= divisor {
                margin_result = abs_notional / divisor;
            } else {
                margin_result = 0;
            }
        }
        2 => {
            max_leverage = position_size.max_leverage as u64;
            divisor = max_leverage.wrapping_mul(2);
            if max_leverage != 0 && abs_notional >= divisor {
                margin_result = abs_notional / divisor;
            } else {
                margin_result = 0;
            }
        }
        3 => {
            adl_divisor_byte = position_size.max_leverage.wrapping_mul(3);
            adl_divisor = adl_divisor_byte as u64;
            divisor = adl_divisor;
            if adl_divisor_byte != 0 && abs_notional >= divisor {
                margin_result = abs_notional / divisor;
            } else {
                margin_result = 0;
            }
        }
        _ => { margin_result = 0; }
    }

    let mut result: MarginRequirementResult = unsafe { core::mem::zeroed() };
    let result_1 = &mut result;
    let mut accum_margin: u64 = 0;
    let mut accum_margin_1: u64 = 0;
    let mut signed_notional: i64 = 0;
    let mut pos_notional: i64 = 0;

    if position_size.margin.margin_type == 3 {
        result_1.notional_lo = abs_notional_1 as u64;
        result_1.price_lo = price_oqu_unit;
        result_1.notional_hi = price_oqu_tag_2;
        result_1.size_lo = oracle_price_val;
        result_1.size_hi = margin_result;
        result_1.margin_type = abs_notional;
        result_1.margin_req = 0;
        result_1.abs_notional_lo = 0;
        result_1.kind = 3;
    } else {
        result_1.margin_addl = position_size.margin.margin_addl;
        result_1.margin_type = position_size.margin.margin_type;
        accum_margin_1 = position_size.margin.margin_addl;
        accum_margin = accum_margin_1;
        signed_notional = abs_notional_1.wrapping_add(accum_margin_1 as i64);
        let (rax_3, rdx_1) =
            unsafe { option_unit_qty_add_a(&price_oqu_unit, &oqu_scratch) };
        let rdi_2 = if signed_notional == 0 { 2 } else { rax_3 };
        let rax_3 = if signed_notional <= 0 { 2 } else { rax_3 };
        if signed_notional > 0 {
            pos_notional = signed_notional;
        }
        result_1.kind = rdi_2;
        result_1.price_lo = rdx_1;
        result_1.price_hi = signed_notional as u64;
        result_1.notional_lo = rax_3;
        result_1.notional_hi = rdx_1;
        result_1.size_lo = pos_notional as u64;
        result_1.size_hi = price_oqu_tag;
        result_1.abs_notional_lo = price_oqu_tag_2;
        result_1.abs_notional_hi = oracle_price_val;
        result_1.flags = margin_result;
    }
    result_1.mark_lo = price_oqu_tag;
    result_1.mark_hi = oracle_price_val_1;

    let _ = (oracle_price_val_2, leverage, adl_divisor, accum_margin);

    result
}

use std::collections::BTreeMap;

pub struct UnitQty { pub unit: u64, pub qty: i64 }
pub struct AssetPosition { pub coin: u64, pub size: i64, pub entry_px: u64 }

pub struct AccountState {
    pub equity: Option<UnitQty>,
    pub isolated_equity: Option<UnitQty>,
    pub positions: BTreeMap<u64, AssetPosition>,
}

pub struct MarginResult {
    pub total_equity: Option<UnitQty>,
    pub margin_req: Option<UnitQty>,
    pub abs_notional: Option<UnitQty>,
    pub raw_equity: Option<UnitQty>,
}

pub fn compute_user_margin_and_shortfall(user_state: &AccountState, oracle_data: &Vec<u64>) -> MarginResult {
    let mut total_equity_unit: u64 = 0;
    let mut total_equity_val: i64 = 0;
    let margin_req_unit: u64 = 0;
    let mut margin_req_value: i64 = 0;
    let abs_ntl_unit: u64 = 0;
    let mut abs_ntl_val: i64 = 0;
    let mut acct_equity_value: i64 = 0;
    if let Some(ref _e) = user_state.equity {
        total_equity_unit = _e.unit;
        acct_equity_value = _e.qty;
    }
    let oracle_prices_len = oracle_data.len();
    let mut btree_cursor = user_state.positions.iter();
    while let Some((asset_key, position_buf)) = btree_cursor.next() {
        let leverage: u64 = *asset_key;
        if (leverage as usize) >= oracle_prices_len { continue; }
        let signed_notional: i64 = position_buf.size * (oracle_data[leverage as usize] as i64);
        total_equity_val += signed_notional;
        margin_req_value += if signed_notional < 0 { -signed_notional } else { signed_notional };
        abs_ntl_val += if signed_notional < 0 { -signed_notional } else { signed_notional };
    }
    total_equity_val += acct_equity_value;
    MarginResult {
        total_equity: Some(UnitQty { unit: total_equity_unit, qty: total_equity_val }),
        margin_req: Some(UnitQty { unit: margin_req_unit, qty: margin_req_value }),
        abs_notional: Some(UnitQty { unit: abs_ntl_unit, qty: abs_ntl_val }),
        raw_equity: Some(UnitQty { unit: total_equity_unit, qty: acct_equity_value }),
    }
}

