#[repr(C)]
pub struct Out { pub a: u64, pub b: u64, pub c: i64 }

#[repr(C)]
pub struct UserState {
    _p0: [u8; 0x30],
    pub positions_root: *mut Node,
    pub positions_height: u64,
    _p1: [u8; 0x8],
}

#[repr(C)]
pub struct Node {
    _p0: [u8; 0x6f0],
    pub keys: [u64; 32],
    pub leaf: u16,
}

#[repr(C)]
pub struct OracleData {
    _p0: u64,
    pub oracle_pxs_ptr: *const u8,
    pub oracle_len: u64,
}

extern "C" {
    fn compute_user_margin_and_shortfall(out: *mut Out, us: *const UserState, od: *const OracleData, p: *const ());
    fn compute_margin_requirement_by_mode(out: *mut [u8; 0xa0], lev: *const [u8; 0xa0], sn: *const u8, mm: u32, lev_int: i32);
    fn option_unit_qty_add_a(a: *mut [u8; 0xa0], b: *mut [u8; 0xa0]) -> u128;
    fn unwrap_failed() -> !;
    fn panic_overflow_sub() -> !;
    fn panic_index_out_of_bounds(i: u64, l: u64) -> !;
}

#[no_mangle]
pub unsafe extern "C" fn compute_account_value_for_direction(
    result: *mut Out,
    user_state: *const UserState,
    is_isolated: u8,
    asset_idx: u64,
    margin_mode: u32,
    oracle_data: *const OracleData,
) -> *mut Out {
    let mut lhs_1 = [0u8; 0xa0];
    let mut lhs = [0u8; 0xa0];
    let equity_qty_value_1: i64;
    let mut margin_req_value_1: i64;
    let mut margin_req_tag_1: u64;
    let margin_req_unit_1: u64;

    if (is_isolated & 1) == 0 {
        compute_user_margin_and_shortfall(lhs_1.as_mut_ptr() as *mut Out, user_state, oracle_data, core::ptr::null());
        let h = lhs_1.as_ptr() as *const Out;
        let equity_qty_value: i64 = (*h).c;
        equity_qty_value_1 = equity_qty_value;
        core::ptr::copy_nonoverlapping(lhs_1.as_ptr(), lhs.as_mut_ptr(), 0xa0);
        let margin_req_tag: u64 = (*h).a;
        margin_req_tag_1 = margin_req_tag;
        let margin_req_unit: u64 = (*h).b;
        margin_req_unit_1 = margin_req_unit;
        let margin_req_value: i64 = (*h).c;
        margin_req_value_1 = margin_req_value;
    } else {
        let mut rax = (*user_state).positions_root;
        let mut rdx = (*user_state).positions_height;
        if rax.is_null() {
            *result = Out { a: 2, b: 0, c: 0 };
            return result;
        }
        let mut r11_1: u64;
        let mut rdi_2: u64;
        let found_idx: u64;
        loop {
            let r10_1: u64 = (*rax).leaf as u64;
            rdi_2 = u64::MAX;
            r11_1 = 0;
            let mut key_mismatch: bool = true;
            let mut i: u64 = 0;
            while ((r10_1 << 5).wrapping_mul(5)) != r11_1 {
                let position_node_key: u64 = (*rax).keys[i as usize];
                key_mismatch = position_node_key != asset_idx;
                if position_node_key > asset_idx { key_mismatch = true; }
                if !key_mismatch { rdi_2 = i; break; }
                i = i.wrapping_add(1);
                r11_1 = r11_1.wrapping_add(0xa0);
            }
            if rdi_2 == u64::MAX { rdi_2 = r10_1; }
            let temp3_1 = rdx;
            rdx = rdx.wrapping_sub(1);
            if !key_mismatch { found_idx = rdi_2; break; }
            if temp3_1 < 1 {
                *result = Out { a: 2, b: 0, c: 0 };
                return result;
            }
            let child_off = 0x748 + (rdi_2 as usize) * 8;
            let child_pp = (rax as *const u8).add(child_off) as *const *mut Node;
            rax = *child_pp;
        }
        let lev_ptr = (rax as *const u8).add((found_idx as usize).wrapping_mul(0xa0));
        let leverage: i32 = *(lev_ptr as *const i32);
        core::ptr::copy_nonoverlapping(lev_ptr, lhs_1.as_mut_ptr(), 0xa0);
        let len: u64 = (*oracle_data).oracle_len;
        let index: u64 = asset_idx;
        if len <= index { panic_index_out_of_bounds(index, len); }
        let oracle_pxs_ptr = (*oracle_data).oracle_pxs_ptr;
        let oracle_offset: usize = (index as usize).wrapping_mul(0x60);
        let signed_notional_ptr = oracle_pxs_ptr.add(oracle_offset).add(0x30);
        let mut result_1 = [0u8; 0xa0];
        compute_margin_requirement_by_mode(&mut result_1, &lhs_1, signed_notional_ptr, margin_mode, leverage);
        let r1_h = result_1.as_ptr() as *const Out;
        if (*r1_h).a == 3 { unwrap_failed(); }
        let equity_qty_value_2: i64 = (*r1_h).c;
        equity_qty_value_1 = equity_qty_value_2;
        core::ptr::copy_nonoverlapping(result_1.as_ptr(), lhs.as_mut_ptr(), 0xa0);
        let margin_req_tag_2: u64 = (*r1_h).a;
        margin_req_tag_1 = margin_req_tag_2;
        let margin_req_unit_2: u64 = (*r1_h).b;
        margin_req_unit_1 = margin_req_unit_2;
        let margin_req_value_3: i64 = (*r1_h).c;
        margin_req_value_1 = margin_req_value_3;
    }

    if margin_req_value_1 == 0 { margin_req_tag_1 = 2; }
    let lhs1_h = lhs_1.as_mut_ptr() as *mut Out;
    (*lhs1_h).b = margin_req_unit_1;
    (*lhs1_h).a = margin_req_tag_1;
    let equity_minus_margin: i64 = match equity_qty_value_1.checked_sub(margin_req_value_1) {
        Some(v) => v,
        None => panic_overflow_sub(),
    };
    let combined = option_unit_qty_add_a(&mut lhs, &mut lhs_1);
    let rax_1_v: u64 = combined as u64;
    let rdx_1: u64 = (combined >> 64) as u64;
    let rax_1: u64 = if equity_minus_margin == 0 { 2 } else { rax_1_v };
    (*result).b = rdx_1;
    (*result).c = equity_minus_margin;
    (*result).a = rax_1;
    result
}
